204	            return global.throw("Converting circular structure to JSON5", .{});
205	        }
206	        defer _ = this.visiting.remove(unwrapped);
207	
208	        if (unwrapped.isArray()) {
209	            try this.stringifyArray(global, unwrapped);
210	        } else {
211	            try this.stringifyObject(global, unwrapped);
212	        }
213	    }
