533	    fn appendDoubleQuotedString(this: *Stringifier, str: String) void {
534	        this.builder.append(.lchar, '"');
535	
536	        for (0..str.length()) |i| {
537	            const c = str.charAt(i);
538	
539	            switch (c) {
540	                0x00 => this.builder.append(.latin1, "\\0"),
541	                0x01 => this.builder.append(.latin1, "\\x01"),
542	                0x02 => this.builder.append(.latin1, "\\x02"),
543	                0x03 => this.builder.append(.latin1, "\\x03"),
544	                0x04 => this.builder.append(.latin1, "\\x04"),
545	                0x05 => this.builder.append(.latin1, "\\x05"),
546	                0x06 => this.builder.append(.latin1, "\\x06"),
547	                0x07 => this.builder.append(.latin1, "\\a"), // bell
548	                0x08 => this.builder.append(.latin1, "\\b"), // backspace
549	                0x09 => this.builder.append(.latin1, "\\t"), // tab
550	                0x0a => this.builder.append(.latin1, "\\n"), // line feed
551	                0x0b => this.builder.append(.latin1, "\\v"), // vertical tab
552	                0x0c => this.builder.append(.latin1, "\\f"), // form feed
553	                0x0d => this.builder.append(.latin1, "\\r"), // carriage return
554	                0x0e => this.builder.append(.latin1, "\\x0e"),
555	                0x0f => this.builder.append(.latin1, "\\x0f"),
556	                0x10 => this.builder.append(.latin1, "\\x10"),
557	                0x11 => this.builder.append(.latin1, "\\x11"),
558	                0x12 => this.builder.append(.latin1, "\\x12"),
559	                0x13 => this.builder.append(.latin1, "\\x13"),
560	                0x14 => this.builder.append(.latin1, "\\x14"),
561	                0x15 => this.builder.append(.latin1, "\\x15"),
562	                0x16 => this.builder.append(.latin1, "\\x16"),
563	                0x17 => this.builder.append(.latin1, "\\x17"),
564	                0x18 => this.builder.append(.latin1, "\\x18"),
565	                0x19 => this.builder.append(.latin1, "\\x19"),
566	                0x1a => this.builder.append(.latin1, "\\x1a"),
567	                0x1b => this.builder.append(.latin1, "\\e"), // escape
568	                0x1c => this.builder.append(.latin1, "\\x1c"),
569	                0x1d => this.builder.append(.latin1, "\\x1d"),
570	                0x1e => this.builder.append(.latin1, "\\x1e"),
571	                0x1f => this.builder.append(.latin1, "\\x1f"),
572	                0x22 => this.builder.append(.latin1, "\\\""), // "
573	                0x5c => this.builder.append(.latin1, "\\\\"), // \
574	                0x7f => this.builder.append(.latin1, "\\x7f"), // delete
575	                0x85 => this.builder.append(.latin1, "\\N"), // next line
576	                0xa0 => this.builder.append(.latin1, "\\_"), // non-breaking space
577	                0xa8 => this.builder.append(.latin1, "\\L"), // line separator
578	                0xa9 => this.builder.append(.latin1, "\\P"), // paragraph separator
579	
580	                0x20...0x21,
581	                0x23...0x5b,
582	                0x5d...0x7e,
583	                0x80...0x84,
584	                0x86...0x9f,
585	                0xa1...0xa7,
586	                0xaa...std.math.maxInt(u16),
587	                => this.builder.append(.uchar, c),
588	            }
589	        }
590	
591	        this.builder.append(.lchar, '"');
592	    }
