267	    const StringifyError = JSError || bun.StackOverflow;
268	
269	    pub fn stringify(this: *Stringifier, global: *JSGlobalObject, value: JSValue) StringifyError!void {
270	        if (!this.stack_check.isSafeToRecurse()) {
271	            return error.StackOverflow;
272	        }
273	
274	        const unwrapped = try value.unwrapBoxedPrimitive(global);
275	
276	        if (unwrapped.isNull()) {
277	            this.builder.append(.latin1, "null");
278	            return;
279	        }
280	
281	        if (unwrapped.isNumber()) {
282	            if (unwrapped.isInt32()) {
283	                this.builder.append(.int, unwrapped.asInt32());
284	                return;
285	            }
286	
287	            const num = unwrapped.asNumber();
288	            if (std.math.isNegativeInf(num)) {
289	                this.builder.append(.latin1, "-.inf");
290	                // } else if (std.math.isPositiveInf(num)) {
291	                //     builder.append(.latin1, "+.inf");
292	            } else if (std.math.isInf(num)) {
293	                this.builder.append(.latin1, ".inf");
294	            } else if (std.math.isNan(num)) {
295	                this.builder.append(.latin1, ".nan");
296	            } else if (std.math.isNegativeZero(num)) {
297	                this.builder.append(.latin1, "-0");
298	            } else if (std.math.isPositiveZero(num)) {
299	                this.builder.append(.latin1, "+0");
300	            } else {
301	                this.builder.append(.double, num);
302	            }
303	            return;
304	        }
305	
306	        if (unwrapped.isBigInt()) {
307	            return global.throw("YAML.stringify cannot serialize BigInt", .{});
308	        }
309	
310	        if (unwrapped.isBoolean()) {
311	            if (unwrapped.asBoolean()) {
312	                this.builder.append(.latin1, "true");
313	            } else {
314	                this.builder.append(.latin1, "false");
315	            }
316	            return;
317	        }
318	
319	        if (unwrapped.isString()) {
320	            const value_str = try unwrapped.toBunString(global);
321	            defer value_str.deref();
322	
323	            this.appendString(value_str);
324	            return;
325	        }
326	
327	        if (comptime Environment.ci_assert) {
328	            bun.assertWithLocation(unwrapped.isObject(), @src());
329	        }
330	
331	        const has_anchor: ?*AnchorAlias = has_anchor: {
332	            const anchor = this.known_collections.getPtr(unwrapped) orelse {
333	                break :has_anchor null;
334	            };
335	
336	            if (!anchor.used) {
337	                break :has_anchor null;
338	            }
339	
340	            break :has_anchor anchor;
341	        };
342	
343	        if (has_anchor) |anchor| {
344	            this.builder.append(.lchar, if (anchor.anchored) '*' else '&');
345	
346	            switch (anchor.name) {
347	                .root => {
348	                    this.builder.append(.latin1, "root");
349	                },
350	                .array_item => {
351	                    this.builder.append(.latin1, "item");
352	                    this.builder.append(.usize, anchor.name.array_item);
353	                },
354	                .prop_value => |prop_value| {
355	                    if (prop_value.prop_name.length() == 0) {
356	                        this.builder.append(.latin1, "value");
357	                        this.builder.append(.usize, prop_value.counter);
358	                    } else {
359	                        this.builder.append(.string, anchor.name.prop_value.prop_name);
360	                        if (anchor.name.prop_value.counter != 0) {
361	                            this.builder.append(.usize, anchor.name.prop_value.counter);
362	                        }
363	                    }
364	                },
365	            }
366	
367	            if (anchor.anchored) {
368	                return;
369	            }
370	
371	            switch (this.space) {
372	                .minified => {
373	                    this.builder.append(.lchar, ' ');
374	                },
375	                .number, .str => {
376	                    this.newline();
377	                },
378	            }
379	            anchor.anchored = true;
380	        }
381	
382	        if (unwrapped.isArray()) {
383	            var iter = try unwrapped.arrayIterator(global);
384	
385	            if (iter.len == 0) {
386	                this.builder.append(.latin1, "[]");
387	                return;
388	            }
389	
390	            switch (this.space) {
391	                .minified => {
392	                    this.builder.append(.lchar, '[');
393	                    var first = true;
394	                    while (try iter.next()) |item| {
395	                        if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
396	                            continue;
397	                        }
398	
399	                        if (!first) {
400	                            this.builder.append(.lchar, ',');
401	                        }
402	                        first = false;
403	
404	                        try this.stringify(global, item);
405	                    }
406	                    this.builder.append(.lchar, ']');
407	                },
408	                .number, .str => {
409	                    this.builder.ensureUnusedCapacity(iter.len * "- ".len);
410	                    var first = true;
411	                    while (try iter.next()) |item| {
412	                        if (item.isUndefined() or item.isSymbol() or item.isFunction()) {
413	                            continue;
414	                        }
415	
416	                        if (!first) {
417	                            this.newline();
418	                        }
419	                        first = false;
420	
421	                        this.builder.append(.latin1, "- ");
422	
423	                        // don't need to print a newline here for any value
424	
425	                        this.indent += 1;
426	                        try this.stringify(global, item);
427	                        this.indent -= 1;
428	                    }
429	                },
430	            }
431	
432	            return;
433	        }
434	
435	        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
436	            global,
437	            try unwrapped.toObject(global),
438	        );
439	        defer iter.deinit();
440	
441	        if (iter.len == 0) {
442	            this.builder.append(.latin1, "{}");
443	            return;
444	        }
445	
446	        switch (this.space) {
447	            .minified => {
448	                this.builder.append(.lchar, '{');
449	                var first = true;
450	                while (try iter.next()) |prop_name| {
451	                    if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
452	                        continue;
453	                    }
454	
455	                    if (!first) {
456	                        this.builder.append(.lchar, ',');
457	                    }
458	                    first = false;
459	
460	                    this.appendString(prop_name);
461	                    this.builder.append(.latin1, ": ");
462	
463	                    try this.stringify(global, iter.value);
464	                }
465	                this.builder.append(.lchar, '}');
466	            },
467	            .number, .str => {
468	                this.builder.ensureUnusedCapacity(iter.len * ": ".len);
469	
470	                var first = true;
471	                while (try iter.next()) |prop_name| {
472	                    if (iter.value.isUndefined() or iter.value.isSymbol() or iter.value.isFunction()) {
473	                        continue;
474	                    }
475	
476	                    if (!first) {
477	                        this.newline();
478	                    }
479	                    first = false;
480	
481	                    this.appendString(prop_name);
482	                    this.builder.append(.latin1, ": ");
483	
484	                    this.indent += 1;
485	
486	                    if (propValueNeedsNewline(iter.value)) {
487	                        this.newline();
488	                    }
489	
490	                    try this.stringify(global, iter.value);
491	                    this.indent -= 1;
492	                }
493	                if (first) {
494	                    this.builder.append(.latin1, "{}");
495	                }
496	            },
497	        }
498	    }
