pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();

    const src = input_slice.slice();

    // Root object and current section target
    const root = JSValue.createEmptyObject(globalThis, 0);
    var current = root;

    var iter = std.mem.splitScalar(u8, src, '\n');
    while (iter.next()) |raw_line| {
        const line = stripCR(raw_line);

        // Skip blank lines
        const trimmed = bun.strings.trim(line, " \t");
        if (trimmed.len == 0) continue;

        // Skip comment lines
        if (trimmed[0] == ';' or trimmed[0] == '#') continue;

        // Section header: [section]
        if (trimmed[0] == '[') {
            if (std.mem.indexOfScalar(u8, trimmed, ']')) |close| {
                if (close > 1) {
                    // Verify rest after ] is whitespace only
                    const after_bracket = bun.strings.trim(trimmed[close + 1 ..], " \t");
                    if (after_bracket.len == 0) {
                        const section_name = trimmed[1..close];
                        // Check if section already exists
                        const name_str = bun.String.createUTF8(section_name);
                        defer name_str.deref();
                        const existing = root.getWithString(globalThis, name_str);
                        if (existing != .zero and !existing.isUndefined()) {
                            current = existing;
                        } else {
                            const section_obj = JSValue.createEmptyObject(globalThis, 0);
                            try root.putMayBeIndex(globalThis, &name_str, section_obj);
                            current = section_obj;
                        }
                        continue;
                    }
                }
            }
            // If bracket parsing failed, fall through and treat as key=value
        }

        // Key=value pair
        if (std.mem.indexOfScalar(u8, trimmed, '=')) |eq_idx| {
            const raw_key = bun.strings.trim(trimmed[0..eq_idx], " \t");
            if (raw_key.len == 0) continue;

            const raw_val = if (eq_idx + 1 < trimmed.len)
                bun.strings.trim(trimmed[eq_idx + 1 ..], " \t")
            else
                "";

            const val = coerceValue(globalThis, stripQuotes(raw_val));
            const key_str = bun.String.createUTF8(raw_key);
            defer key_str.deref();
            try current.putMayBeIndex(globalThis, &key_str, val);
        } else {
            // Key without value → true
            const raw_key = bun.strings.trim(trimmed, " \t");
            if (raw_key.len == 0) continue;
            const key_str = bun.String.createUTF8(raw_key);
            defer key_str.deref();
            try current.putMayBeIndex(globalThis, &key_str, JSValue.jsBoolean(true));
