import { describe, expect, test } from "bun:test";

describe("Bun.INI.parse", () => {
  test("basic key=value pairs", () => {
    const result = Bun.INI.parse("name = my-app\nversion = 1.0");
    expect(result).toEqual({ name: "my-app", version: 1.0 });
  });

  test("sections become nested objects", () => {
    const ini = `
[database]
host = localhost
port = 5432
`;
    const result = Bun.INI.parse(ini);
    expect(result).toEqual({ database: { host: "localhost", port: 5432 } });
  });

  test("mixed top-level and sections", () => {
    const ini = `
name = my-app
debug = true

[database]
host = localhost
port = 5432
`;
    const result = Bun.INI.parse(ini);
    expect(result).toEqual({
      name: "my-app",
      debug: true,
      database: { host: "localhost", port: 5432 },
    });
  });

  test("semicolon comments are ignored", () => {
    const ini = `; this is a comment
key = value`;
    const result = Bun.INI.parse(ini);
    expect(result).toEqual({ key: "value" });
  });

  test("hash comments are ignored", () => {
    const ini = `# this is a comment
key = value`;
    const result = Bun.INI.parse(ini);
    expect(result).toEqual({ key: "value" });
  });

