18	    callframe: *jsc.CallFrame,
19	) bun.JSError!jsc.JSValue {
20	    const input_value = callframe.argument(0);
21	    if (input_value.isEmptyOrUndefinedOrNull()) {
22	        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
23	    }
24	
