26	    defer input_slice.deinit();
27	
28	    const src = input_slice.slice();
29	
30	    // Root object and current section target
31	    const root = JSValue.createEmptyObject(globalThis, 0);
32	    var current = root;
33	
34	    var iter = std.mem.splitScalar(u8, src, '\n');
35	    while (iter.next()) |raw_line| {
36	        const line = stripCR(raw_line);
37	
38	        // Skip blank lines
39	        const trimmed = bun.strings.trim(line, " \t");
40	        if (trimmed.len == 0) continue;
41	
42	        // Skip comment lines
43	        if (trimmed[0] == ';' or trimmed[0] == '#') continue;
44	
45	        // Section header: [section]
46	        if (trimmed[0] == '[') {
47	            if (std.mem.indexOfScalar(u8, trimmed, ']')) |close| {
48	                if (close > 1) {
49	                    // Verify rest after ] is whitespace only
50	                    const after_bracket = bun.strings.trim(trimmed[close + 1 ..], " \t");
51	                    if (after_bracket.len == 0) {
52	                        const section_name = trimmed[1..close];
53	                        // Check if section already exists
54	                        const name_str = bun.String.createUTF8(section_name);
55	                        defer name_str.deref();
56	                        const existing = root.getWithString(globalThis, name_str);
57	                        if (existing != .zero and !existing.isUndefined()) {
58	                            current = existing;
59	                        } else {
60	                            const section_obj = JSValue.createEmptyObject(globalThis, 0);
61	                            try root.putMayBeIndex(globalThis, &name_str, section_obj);
62	                            current = section_obj;
63	                        }
64	                        continue;
