116	fn coerceValue(globalThis: *jsc.JSGlobalObject, val: []const u8) jsc.JSValue {
117	    if (val.len == 0) return bun.String.createUTF8ForJS(globalThis, "");
118	
119	    // Boolean coercion
120	    if (bun.strings.eqlComptime(val, "true")) return JSValue.jsBoolean(true);
121	    if (bun.strings.eqlComptime(val, "false")) return JSValue.jsBoolean(false);
122	
