126	    // Number coercion: try integer first, then float
127	    if (parseInt(val)) |int_val| {
128	        return JSValue.jsNumber(int_val);
129	    }
130	    if (parseFloat(val)) |float_val| {
131	        return JSValue.jsNumber(float_val);
132	    }
133	
134	    // Default: string
135	    return bun.String.createUTF8ForJS(globalThis, val);
136	}
