138	fn parseInt(val: []const u8) ?i64 {
139	    if (val.len == 0) return null;
140	    // Don't parse things like "123.456" or "1e5" as integers
141	    for (val, 0..) |c, i| {
142	        switch (c) {
143	            '0'...'9' => {},
144	            '-', '+' => if (i != 0) return null,
145	            else => return null,
146	        }
147	    }
148	    return std.fmt.parseInt(i64, val, 10) catch null;
149	}
