151	fn parseFloat(val: []const u8) ?f64 {
152	    if (val.len == 0) return null;
153	    // Must contain a dot or 'e'/'E' to be considered a float (not an integer)
154	    var has_dot = false;
155	    var has_e = false;
156	    for (val) |c| {
157	        switch (c) {
158	            '.' => has_dot = true,
159	            'e', 'E' => has_e = true,
160	            else => {},
161	        }
162	    }
163	    if (!has_dot and !has_e) return null;
164	    return std.fmt.parseFloat(f64, val) catch null;
165	}
