pub fn create(globalThis: *jsc.JSGlobalObject) jsc.JSValue {
    const object = JSValue.createEmptyObject(globalThis, 2);
    object.put(
        globalThis,
        ZigString.static("parse"),
        jsc.JSFunction.create(globalThis, "parse", parse, 1, .{}),
    );
    object.put(
        globalThis,
        ZigString.static("stringify"),
        jsc.JSFunction.create(globalThis, "stringify", stringify, 1, .{}),
    );
    return object;
}

pub fn parse(
    globalThis: *jsc.JSGlobalObject,
    callframe: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const input_value = callframe.argument(0);
    if (input_value.isEmptyOrUndefinedOrNull()) {
        return globalThis.throwInvalidArguments("Expected a string to parse", .{});
    }

    var input_slice = try input_value.toSlice(globalThis, bun.default_allocator);
    defer input_slice.deinit();

    const src = input_slice.slice();

    // Root object and current section target
    const root = JSValue.createEmptyObject(globalThis, 0);
    var current = root;

    var iter = std.mem.splitScalar(u8, src, '\n');
    while (iter.next()) |raw_line| {
        const line = stripCR(raw_line);

        // Skip blank lines
        const trimmed = bun.strings.trim(line, " \t");
        if (trimmed.len == 0) continue;

        // Skip comment lines
        if (trimmed[0] == ';' or trimmed[0] == '#') continue;

        // Section header: [section]
        if (trimmed[0] == '[') {
            if (std.mem.indexOfScalar(u8, trimmed, ']')) |close| {
                if (close > 1) {
                    // Verify rest after ] is whitespace only
                    const after_bracket = bun.strings.trim(trimmed[close + 1 ..], " \t");
                    if (after_bracket.len == 0) {
                        const section_name = trimmed[1..close];
                        // Check if section already exists
                        const name_str = bun.String.createUTF8(section_name);
                        defer name_str.deref();
                        const existing = root.getWithString(globalThis, name_str);
                        if (existing != .zero and !existing.isUndefined()) {
                            current = existing;
                        } else {
                            const section_obj = JSValue.createEmptyObject(globalThis, 0);
                            try root.putMayBeIndex(globalThis, &name_str, section_obj);
                            current = section_obj;
                        }
                        continue;
                    }
                }
            }
            // If bracket parsing failed, fall through and treat as key=value
        }

        // Key=value pair
        if (std.mem.indexOfScalar(u8, trimmed, '=')) |eq_idx| {
            const raw_key = bun.strings.trim(trimmed[0..eq_idx], " \t");
            if (raw_key.len == 0) continue;

            const raw_val = if (eq_idx + 1 < trimmed.len)
                bun.strings.trim(trimmed[eq_idx + 1 ..], " \t")
            else
                "";

            const val = coerceValue(globalThis, stripQuotes(raw_val));
            const key_str = bun.String.createUTF8(raw_key);
            defer key_str.deref();
            try current.putMayBeIndex(globalThis, &key_str, val);
        } else {
            // Key without value → true
            const raw_key = bun.strings.trim(trimmed, " \t");
            if (raw_key.len == 0) continue;
            const key_str = bun.String.createUTF8(raw_key);
            defer key_str.deref();
            try current.putMayBeIndex(globalThis, &key_str, JSValue.jsBoolean(true));
        }
    }

    return root;
}

fn stripCR(line: []const u8) []const u8 {
    if (line.len > 0 and line[line.len - 1] == '\r') {
        return line[0 .. line.len - 1];
    }
    return line;
}

fn stripQuotes(val: []const u8) []const u8 {
    if (val.len >= 2) {
        if ((val[0] == '"' and val[val.len - 1] == '"') or
            (val[0] == '\'' and val[val.len - 1] == '\''))
        {
            return val[1 .. val.len - 1];
        }
    }
    return val;
}

fn coerceValue(globalThis: *jsc.JSGlobalObject, val: []const u8) jsc.JSValue {
    if (val.len == 0) return bun.String.createUTF8ForJS(globalThis, "");

    // Boolean coercion
    if (bun.strings.eqlComptime(val, "true")) return JSValue.jsBoolean(true);
    if (bun.strings.eqlComptime(val, "false")) return JSValue.jsBoolean(false);

    // Null coercion
    if (bun.strings.eqlComptime(val, "null")) return .null;

    // Number coercion: try integer first, then float
    if (parseInt(val)) |int_val| {
        return JSValue.jsNumber(int_val);
    }
    if (parseFloat(val)) |float_val| {
        return JSValue.jsNumber(float_val);
    }

    // Default: string
    return bun.String.createUTF8ForJS(globalThis, val);
}

fn parseInt(val: []const u8) ?i64 {
    if (val.len == 0) return null;
    // Don't parse things like "123.456" or "1e5" as integers
    for (val, 0..) |c, i| {
        switch (c) {
            '0'...'9' => {},
            '-', '+' => if (i != 0) return null,
            else => return null,
        }
    }
    return std.fmt.parseInt(i64, val, 10) catch null;
}

fn parseFloat(val: []const u8) ?f64 {
    if (val.len == 0) return null;
    // Must contain a dot or 'e'/'E' to be considered a float (not an integer)
    var has_dot = false;
    var has_e = false;
    for (val) |c| {
        switch (c) {
            '.' => has_dot = true,
            'e', 'E' => has_e = true,
            else => {},
        }
    }
    if (!has_dot and !has_e) return null;
    return std.fmt.parseFloat(f64, val) catch null;
}

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    if (value.isUndefined() or value.isSymbol() or value.isFunction()) {
        return .js_undefined;
    }

    if (!value.isObject()) {
        return global.throw("INI.stringify requires an object argument", .{});
    }

    var stringifier: Stringifier = .init();
    defer stringifier.deinit();

    try stringifier.stringifyRoot(global, value);

    return stringifier.builder.toString(global);
}

const Stringifier = struct {
    builder: wtf.StringBuilder,
    visiting: std.AutoHashMapUnmanaged(JSValue, void),
    allocator: std.mem.Allocator,
    has_output: bool,

    const StringifyError = bun.JSError;

    pub fn init() Stringifier {
        return .{
            .builder = .init(),
            .visiting = .empty,
            .allocator = bun.default_allocator,
            .has_output = false,
        };
    }

    pub fn deinit(this: *Stringifier) void {
        this.builder.deinit();
        this.visiting.deinit(this.allocator);
    }

    pub fn stringifyRoot(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
        // Check for circular references
        const gop = this.visiting.getOrPut(this.allocator, value) catch return error.OutOfMemory;
        if (gop.found_existing) {
            return global.throw("Converting circular structure to INI", .{});
        }
        defer _ = this.visiting.remove(value);

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        // First pass: emit top-level non-object properties
        while (try iter.next()) |prop_name| {
            const prop_val = iter.value;
            if (prop_val.isUndefined() or prop_val.isSymbol() or prop_val.isFunction()) {
                continue;
            }
            // Skip objects (including arrays) — handled in second pass
            if (prop_val.isObject()) continue;

            try this.appendPrimitive(global, prop_name, prop_val);
        }

        // Second pass: emit sections for object properties
        iter.reset();
        while (try iter.next()) |prop_name| {
            const prop_val = iter.value;
            if (prop_val.isUndefined() or prop_val.isSymbol() or prop_val.isFunction()) {
                continue;
            }
            if (!prop_val.isObject()) continue;

            if (prop_val.isArray()) {
                return global.throw("INI.stringify does not support arrays", .{});
            }

            try this.stringifySection(global, prop_name, prop_val);
        }
    }

    fn stringifySection(this: *Stringifier, global: *jsc.JSGlobalObject, section_name: bun.String, section_val: JSValue) StringifyError!void {
        // Circular reference check
        const gop = this.visiting.getOrPut(this.allocator, section_val) catch return error.OutOfMemory;
        if (gop.found_existing) {
            return global.throw("Converting circular structure to INI", .{});
        }
        defer _ = this.visiting.remove(section_val);

        // Blank line before section if there was previous output
        if (this.has_output) {
            this.builder.append(.lchar, '\n');
        }

        this.builder.append(.lchar, '[');
        this.builder.append(.string, section_name);
        this.builder.append(.latin1, "]\n");
        this.has_output = true;

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try section_val.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const prop_val = iter.value;
            if (prop_val.isUndefined() or prop_val.isSymbol() or prop_val.isFunction()) {
                continue;
            }
            if (prop_val.isObject()) {
                return global.throw("INI.stringify does not support nesting deeper than one level", .{});
            }

            try this.appendPrimitive(global, prop_name, prop_val);
        }
    }

    fn appendPrimitive(this: *Stringifier, global: *jsc.JSGlobalObject, key: bun.String, value: JSValue) StringifyError!void {
        this.builder.append(.string, key);
        this.builder.append(.latin1, " = ");

        if (value.isNull()) {
            this.builder.append(.latin1, "null");
        } else if (value.isBoolean()) {
            this.builder.append(.latin1, if (value.asBoolean()) "true" else "false");
        } else if (value.isBigInt()) {
            return global.throw("INI.stringify cannot serialize BigInt", .{});
        } else if (value.isNumber()) {
            if (value.isInt32()) {
                this.builder.append(.int, value.asInt32());
            } else {
                this.builder.append(.double, value.asNumber());
            }
        } else if (value.isString()) {
            const str = try value.toBunString(global);
            defer str.deref();
            if (stringNeedsQuoting(str)) {
                this.builder.append(.lchar, '"');
                this.builder.append(.string, str);
                this.builder.append(.lchar, '"');
            } else {
                this.builder.append(.string, str);
            }
        } else {
            // Fallback: convert to string
            const str = try value.toBunString(global);
            defer str.deref();
            this.builder.append(.string, str);
        }

        this.builder.append(.lchar, '\n');
        this.has_output = true;
    }

    fn stringNeedsQuoting(str: bun.String) bool {
        const len = str.length();
        if (len == 0) return true;

        // Check leading/trailing whitespace
        const first = str.charAt(0);
        if (first == ' ' or first == '\t') return true;
        const last = str.charAt(len - 1);
        if (last == ' ' or last == '\t') return true;

        // Check for characters that need quoting
        for (0..len) |i| {
            const c = str.charAt(i);
            switch (c) {
                ';', '#', '\n', '\r', '=' => return true,
                else => {},
            }
        }
        return false;
    }
};

