            '-', '+' => if (i != 0) return null,
            else => return null,
        }
    }
    return std.fmt.parseInt(i64, val, 10) catch null;
}

fn parseFloat(val: []const u8) ?f64 {
    if (val.len == 0) return null;
    // Must contain a dot or 'e'/'E' to be considered a float (not an integer)
    var has_dot = false;
    var has_e = false;
    for (val) |c| {
        switch (c) {
            '.' => has_dot = true,
            'e', 'E' => has_e = true,
            else => {},
        }
    }
    if (!has_dot and !has_e) return null;
    return std.fmt.parseFloat(f64, val) catch null;
}

pub fn stringify(
    global: *jsc.JSGlobalObject,
    callFrame: *jsc.CallFrame,
) bun.JSError!jsc.JSValue {
    const value = callFrame.argument(0);

    if (value.isUndefined() or value.isSymbol() or value.isFunction()) {
        return .js_undefined;
    }

    if (!value.isObject()) {
        return global.throw("INI.stringify requires an object argument", .{});
    }

    var stringifier: Stringifier = .init();
    defer stringifier.deinit();

    try stringifier.stringifyRoot(global, value);

    return stringifier.builder.toString(global);
}

const Stringifier = struct {
    builder: wtf.StringBuilder,
    visiting: std.AutoHashMapUnmanaged(JSValue, void),
    allocator: std.mem.Allocator,
    has_output: bool,

    const StringifyError = bun.JSError;

    pub fn init() Stringifier {
        return .{
            .builder = .init(),
            .visiting = .empty,
            .allocator = bun.default_allocator,
            .has_output = false,
        };
    }

    pub fn deinit(this: *Stringifier) void {
        this.builder.deinit();
        this.visiting.deinit(this.allocator);
    }

    pub fn stringifyRoot(this: *Stringifier, global: *jsc.JSGlobalObject, value: JSValue) StringifyError!void {
        // Check for circular references
        const gop = this.visiting.getOrPut(this.allocator, value) catch return error.OutOfMemory;
        if (gop.found_existing) {
            return global.throw("Converting circular structure to INI", .{});
        }
        defer _ = this.visiting.remove(value);

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try value.toObject(global),
        );
        defer iter.deinit();

        // First pass: emit top-level non-object properties
        while (try iter.next()) |prop_name| {
            const prop_val = iter.value;
            if (prop_val.isUndefined() or prop_val.isSymbol() or prop_val.isFunction()) {
                continue;
            }
            // Skip objects (including arrays) — handled in second pass
            if (prop_val.isObject()) continue;

            try this.appendPrimitive(global, prop_name, prop_val);
        }

        // Second pass: emit sections for object properties
        iter.reset();
        while (try iter.next()) |prop_name| {
            const prop_val = iter.value;
            if (prop_val.isUndefined() or prop_val.isSymbol() or prop_val.isFunction()) {
                continue;
            }
            if (!prop_val.isObject()) continue;

            if (prop_val.isArray()) {
                return global.throw("INI.stringify does not support arrays", .{});
            }

            try this.stringifySection(global, prop_name, prop_val);
        }
    }

    fn stringifySection(this: *Stringifier, global: *jsc.JSGlobalObject, section_name: bun.String, section_val: JSValue) StringifyError!void {
        // Circular reference check
        const gop = this.visiting.getOrPut(this.allocator, section_val) catch return error.OutOfMemory;
        if (gop.found_existing) {
            return global.throw("Converting circular structure to INI", .{});
        }
        defer _ = this.visiting.remove(section_val);

        // Blank line before section if there was previous output
        if (this.has_output) {
            this.builder.append(.lchar, '\n');
        }

        this.builder.append(.lchar, '[');
        this.builder.append(.string, section_name);
        this.builder.append(.latin1, "]\n");
        this.has_output = true;

        var iter: jsc.JSPropertyIterator(.{ .skip_empty_name = false, .include_value = true }) = try .init(
            global,
            try section_val.toObject(global),
        );
        defer iter.deinit();

        while (try iter.next()) |prop_name| {
            const prop_val = iter.value;
            if (prop_val.isUndefined() or prop_val.isSymbol() or prop_val.isFunction()) {
                continue;
            }
            if (prop_val.isObject()) {
                return global.throw("INI.stringify does not support nesting deeper than one level", .{});
            }

            try this.appendPrimitive(global, prop_name, prop_val);
        }
    }

    fn appendPrimitive(this: *Stringifier, global: *jsc.JSGlobalObject, key: bun.String, value: JSValue) StringifyError!void {
        this.builder.append(.string, key);
        this.builder.append(.latin1, " = ");

        if (value.isNull()) {
            this.builder.append(.latin1, "null");
        } else if (value.isBoolean()) {
            this.builder.append(.latin1, if (value.asBoolean()) "true" else "false");
        } else if (value.isBigInt()) {
            return global.throw("INI.stringify cannot serialize BigInt", .{});
        } else if (value.isNumber()) {
            if (value.isInt32()) {
                this.builder.append(.int, value.asInt32());
            } else {
                this.builder.append(.double, value.asNumber());
            }
        } else if (value.isString()) {
            const str = try value.toBunString(global);
            defer str.deref();
            if (stringNeedsQuoting(str)) {
                this.builder.append(.lchar, '"');
                this.builder.append(.string, str);
                this.builder.append(.lchar, '"');
            } else {
                this.builder.append(.string, str);
            }
        } else {
            // Fallback: convert to string
            const str = try value.toBunString(global);
            defer str.deref();
            this.builder.append(.string, str);
        }

        this.builder.append(.lchar, '\n');
        this.has_output = true;
    }

    fn stringNeedsQuoting(str: bun.String) bool {
        const len = str.length();
        if (len == 0) return true;

        // Check leading/trailing whitespace
        const first = str.charAt(0);
        if (first == ' ' or first == '\t') return true;
        const last = str.charAt(len - 1);
        if (last == ' ' or last == '\t') return true;

        // Check for characters that need quoting
        for (0..len) |i| {
            const c = str.charAt(i);
            switch (c) {
                ';', '#', '\n', '\r', '=' => return true,
                else => {},
            }
        }
        return false;
    }
};

